823	        /* right part */
824	        for (; i_out_x < out_tensor_dim; i_out_x++)
825	        {
826	            /* This part implements the im2col function */
827	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
828	            {
829	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
830	                {
831	                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
832	                    {
833	                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
834	                    }
835	                    else
836	                    {
837	                        nn_dup_u8_u16_reordered
838	                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
839	                    }
840	                    pBuffer += in_tensor_ch;
841	                }
842	            }
843	
844	            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
845	            {
846	                pOut =
847	                    nn_mat_mul_kernel_q7_u16_u8_reordered_bias_2sft(ker_weight,
848	                                                                    (u16_t*)in_tmp_buf,
849	                                                                    out_tensor_ch,
850	                                                                    in_tensor_ch * ker_dim * ker_dim,
851	                                                                    pre_rshift,
852	                                                                    out_scale,
853	                                                                    post_rshift,
854	                                                                    bias,
855	                                                                    pOut);
856	                /* counter reset */
857	                pBuffer = (u16_t*)in_tmp_buf;
858	            }
859	        }
860	    }
861	
862	    for (; i_out_y < out_tensor_dim; i_out_y++)
863	    {
864	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
865	        {
866	            /* This part implements the im2col function */
867	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
868	            {
869	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
870	                {
871	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
872	                    {
873	                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
874	                    }
875	                    else
876	                    {
877	                        nn_dup_u8_u16_reordered
878	                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
879	                    }
880	                    pBuffer += in_tensor_ch;
881	                }
882	            }
883	
884	            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
885	            {
886	                pOut =
887	                    nn_mat_mul_kernel_q7_u16_u8_reordered_bias_2sft(ker_weight,
888	                                                                    (u16_t*)in_tmp_buf,
889	                                                                    out_tensor_ch,
890	                                                                    in_tensor_ch * ker_dim * ker_dim,
891	                                                                    pre_rshift,
892	                                                                    out_scale,
893	                                                                    post_rshift,
894	                                                                    bias,
895	                                                                    pOut);
896	                /* counter reset */
897	                pBuffer = (u16_t*)in_tmp_buf;
898	            }
899	        }
900	    }
901	
902	    /* check if there is left-over for compute */
903	    if (pBuffer != (u16_t*)in_tmp_buf)
904	    {
905	        const q7_t *pA = ker_weight;
906	        int       i;
907	
908	        for (i = 0; i < out_tensor_ch; i++)
909	        {
910	            q31_t     sum = bias[i];
911	            u16_t    *pB = (u16_t*)in_tmp_buf;
912	            /* each time it process 4 entries */
913	            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
914	
915	            while (colCnt)
916	            {
917	                q31_t     inA1, inA2;
918	                q31_t     inB1, inB2;
919	
920	                pA = (q7_t *) read_and_pad_reordered((void *)pA, &inA1, &inA2);
921	
922	                inB1 = *__SIMD32(pB)++;
923	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
924	                inB2 = *__SIMD32(pB)++;
925	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
926	
927	                colCnt--;
928	            }
929	            //since in_tensor_ch is multiple of 4 (input constraints), the
930	            //following codes will not be reached
931	            // colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
932	            // while (colCnt)
933	            // {
934	            //     q7_t      inA1 = *pA++;
935	            //     q15_t     inB1 = *pB++;
936	            //     sum += inA1 * inB1;
937	            //     colCnt--;
938	            // }
939	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
940	            *pOut++ = NDS_DSP_SAT((sum >> post_rshift), 8);
941	        }
942	    }
943	#else
944	    uint16_t  i, j, k, l, m, n;
945	    int       conv_out;
946	    long in_row, in_col;
947	
948	    for (i = 0; i < out_tensor_ch; i++)
949	    {
950	        for (j = 0; j < out_tensor_dim; j++)
951	        {
952	            for (k = 0; k < out_tensor_dim; k++)
953	            {
954	                conv_out = bias[i];
955	                for (m = 0; m < ker_dim; m++)
956	                {
957	                    for (n = 0; n < ker_dim; n++)
958	                    {
959	                        // if-for implementation
960	                        in_row = stride * j + m - pad;
961	                        in_col = stride * k + n - pad;
962	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
963	                        {
964	                            for (l = 0; l < in_tensor_ch; l++)
965	                            {
966	                                conv_out +=
967	                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch + l]
968	                                    * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim + n) * in_tensor_ch + l];
969	                            }
970	                        }
971	                    }
972	                }
973	                if (conv_out < 0)
974	                    out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = 0;
975	                else
976	                {
977	                    conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
978	                    out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SAT((conv_out >> post_rshift), 8);
979	                }
980	            }
981	        }
982	    }
983	#endif
984	#endif  //ENA_EMPTY_FUN
985	    /* Return to application */
986	    return 0;
987	}
