 ******************************************************************************/

/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// Convolution Functions
int32_t riscv_nn_conv_HWC_u8_u8_s8_sym_bias_fast(const u8_t * in_tensor,
        const uint16_t in_tensor_dim,
        const uint16_t in_tensor_ch,
        const q7_t * ker_weight,
        const uint16_t out_tensor_ch,
        const uint16_t ker_dim,
        const uint16_t pad,
        const uint16_t stride,
        const q31_t * bias,
        const uint16_t pre_rshift,
        const uint16_t out_scale,
        const uint16_t post_rshift,
        u8_t * out_tensor,
        const uint16_t out_tensor_dim,
        q15_t * in_tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#else
    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
    {
        /* check if the input dimension meets the constraints */
        return -1;
    }

#if defined(ENA_VEC_ISA) && defined(ENA_TILING)
    /* cache is 512KB, type is u8 */
    uint32_t tiling_size = 256;
    /* num of columnar */
    int col_counter = 0;
    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
    unsigned long addr_in_tmp_buf;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from u8_t input
     */
    const long align_byte = 64;
    u8_t *pBuffer = (u8_t*)in_tmp_buf;
    u8_t *pOut = out_tensor;
    q31_t *dst_q31;

    q7_t *src2 = (q7_t *)in_tmp_buf
                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim * ker_dim; //matrix_A's memory space
    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
    addr_in_tmp_buf = (unsigned long)src2;
    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim * ker_dim;
    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
    dst_q31 = (q31_t *)addr_in_tmp_buf;

    /* transpose the kernel_weight for matrix multiplication */
    const long row = out_tensor_ch;
    const long col = ker_dim * ker_dim * in_tensor_ch;
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

    /* This part implements the im256col function */
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        /* Filling 0 for out-of-bound paddings */
                        nn_set_zero_u8(pBuffer, sizeof(u8_t) * in_tensor_ch);
                    }
                    else
                    {
                        /* Copying the pixel data to column */
                        nn_dup_u8(in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }
            col_counter++;

            /* Computation is filed for [tiling_size] columns */
            if (col_counter == tiling_size)
            {
                pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8((u8_t *)in_tmp_buf,
                                                              src2,
                                                              dst_q31,
                                                              pOut,
                                                              col_counter,
                                                              in_tensor_ch * ker_dim * ker_dim,
                                                              out_tensor_ch,
                                                              pre_rshift,
                                                              out_scale,
                                                              post_rshift,
                                                              bias,
                                                              tiling_size);
                /* reset */
                col_counter = 0;
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }

    /* check if there is left-over for compute */
    pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8((u8_t *)in_tmp_buf,
                                                  src2,
                                                  dst_q31,
                                                  pOut,
                                                  col_counter,
                                                  in_tensor_ch * ker_dim * ker_dim,
                                                  out_tensor_ch,
                                                  pre_rshift,
                                                  out_scale,
                                                  post_rshift,
                                                  bias,
                                                  tiling_size);
#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */

    u8_t     *pBuffer = (u8_t*)in_tmp_buf;
    u8_t     *pOut = out_tensor;
    int bound_begin = (pad + stride - 1) / stride;
    int bound_end   = (in_tensor_dim + pad - ker_dim + stride) / stride;

    /*
     *  Here we split the entire matrix into three regions depending on the pad situation
     *    Top: i_out_y from 0 to pad - 1
     * Middle: i_out_y from pad to out_tensor_dim-pad-1
     * Bottom: i_out_y from out_tensor_dim-pad to out_tensor_dim-1
     */

    /* top part */
    for (i_out_y = 0; i_out_y < bound_begin; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8
                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
                        (u8_t*)in_tmp_buf,
                        out_tensor_ch,
                        in_tensor_ch * ker_dim * ker_dim,
                        pre_rshift,
                        out_scale,
                        post_rshift,
                        bias,
                        pOut);
                /* counter reset */
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }

    /* middle part, here we also divide the x into left, mid and right */
    for (; i_out_y < bound_end; i_out_y++)
    {
        /* left part */
        for (i_out_x = 0; i_out_x < bound_begin; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8
                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
                        (u8_t*)in_tmp_buf,
                        out_tensor_ch,
                        in_tensor_ch * ker_dim * ker_dim,
                        pre_rshift,
                        out_scale,
                        post_rshift,
                        bias,
                        pOut);
                /* counter reset */
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }

        /* mid part */
        for (; i_out_x < bound_end; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                nn_dup_u8
                ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
                pBuffer += in_tensor_ch * ker_dim;
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
                        (u8_t*)in_tmp_buf,
                        out_tensor_ch,
                        in_tensor_ch * ker_dim * ker_dim,
                        pre_rshift,
                        out_scale,
                        post_rshift,
                        bias,
                        pOut);
                /* counter reset */
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }

        /* right part */
        for (; i_out_x < out_tensor_dim; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8
                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
                        (u8_t*)in_tmp_buf,
                        out_tensor_ch,
                        in_tensor_ch * ker_dim * ker_dim,
                        pre_rshift,
                        out_scale,
                        post_rshift,
                        bias,
                        pOut);
                /* counter reset */
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }

    for (; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8
                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
                        (u8_t*)in_tmp_buf,
                        out_tensor_ch,
                        in_tensor_ch * ker_dim * ker_dim,
                        pre_rshift,
                        out_scale,
                        post_rshift,
                        bias,
                        pOut);
                /* counter reset */
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }

    /* check if there is left-over for compute */
#ifdef ENA_VEC_ISA
#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
    if (pBuffer != (u8_t *)in_tmp_buf)
    {
        unsigned vl;
        const q7_t *p_wt = ker_weight;
        int       i;
        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;

        // NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        vl = __riscv_vsetvl_e32m1(1);
        // NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum

        for (i = 0; i < out_tensor_ch; i++)
        {
            u8_t      *p_in = (u8_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //clear v0~v7
            vl = __riscv_vsetvl_e32m8(colCnt);
            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);

            while (colCnt2 > 0)
            {
                vl = __riscv_vsetvl_e8m8(colCnt2);
                //load src1
                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
                //load src2
                vuint8m8_t vP_in_u8m8 = __riscv_vle8_v_u8m8(p_in, vl);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                p_wt += vl;
                p_in += vl;
                //set the proper avl/SEW/LMUL values for vd4dot
                vl >>= 2;
                vl = __riscv_vsetvl_e32m8(vl);
                //acc += src1 * src2
                vAccumulator = __riscv_vd4dotsu_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_u8m8, vl);
            }

            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);

            //add bias back
            vl = __riscv_vsetvl_e32m1(1);
            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
            vSum = __riscv_vadd(vSum, vBias, vl);

            //2-stage shift
            vSum = __riscv_vsra(vSum, pre_rshift, vl);
            vSum = __riscv_vmul(vSum, out_scale, vl);
            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);

