            vSum = __riscv_vredsum_tu(vSum, vAcc, vSum, vl);
            //move vr results to gpr
            sum = __riscv_vmv_x(vSum);

            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_ISA_SAT((sum >> post_rshift), 8);
        }
